@app.route('/')
def index():
    """Home page - show login status."""
    if 'user' in session:
        user = session['user']
        return jsonify({
            'authenticated': True,
            'user': user,
            'message': f"Welcome, {user.get('name_id', 'Unknown User')}!"
        })
    return jsonify({
        'authenticated': False,
        'message': 'Please login via SSO',
        'login_url': '/saml/login'
    })


@app.route('/saml/login')
def saml_login():
    """Initiate SAML SSO login by redirecting to the IdP."""
    relay_state = request.args.get('next', '/')
    redirect_url, request_id = SAMLRequest.create_redirect_url(
        relay_state=relay_state
    )

    # Store the request ID in session for InResponseTo validation
    session['saml_request_id'] = request_id
    session['saml_relay_state'] = relay_state

    return redirect(redirect_url)


@app.route('/saml/acs', methods=['POST'])
def saml_acs():
    """
    Assertion Consumer Service - receives and processes the SAML Response
    from the Identity Provider.
    """
    saml_response_b64 = request.form.get('SAMLResponse')
    relay_state = request.form.get('RelayState', '/')

    if not saml_response_b64:
        return make_response(
            jsonify({'error': 'No SAMLResponse found in request'}), 400
        )

    try:
        # Parse and validate the SAML response
        saml_response = SAMLResponse(
            raw_response=saml_response_b64,
            idp_cert_pem=IDP_CONFIG['certificate'],
        )
        saml_response.validate()

        # Extract user data
        user_data = saml_response.get_user_data()

        # Authenticate the user - store in session
        session['user'] = user_data
        session['authenticated'] = True
        session['saml_session_index'] = user_data.get('session_index')

        # Clean up SAML request tracking
        session.pop('saml_request_id', None)
        session.pop('saml_relay_state', None)

        # Log successful authentication
        app.logger.info(
            f"User authenticated via SAML SSO: {user_data.get('name_id')}"
        )

        return redirect(relay_state)

    except SAMLError as e:
        app.logger.error(f"SAML authentication failed: {e}")
        return make_response(
            jsonify({'error': 'Authentication failed', 'detail': str(e)}), 403
        )
    except Exception as e:
        app.logger.error(f"Unexpected error during SAML processing: {e}")
        return make_response(
            jsonify({'error': 'Internal server error'}), 500
        )


@app.route('/saml/logout', methods=['GET', 'POST'])
def saml_logout():
    """Handle logout - clear session."""
    user = session.get('user', {})
    app.logger.info(
        f"User logged out: {user.get('name_id', 'Unknown')}"
    )

    session.clear()

    return jsonify({
        'message': 'Successfully logged out',
        'login_url': '/saml/login'
    })


@app.route('/saml/metadata')
def saml_metadata():
    """
    Serve the SP metadata XML. 
    IdP administrators use this to configure the trust relationship.
    """
    metadata = f"""<?xml version="1.0" encoding="UTF-8"?>
<md:EntityDescriptor
    xmlns:md="urn:oasis:names:tc:SAML:2.0:metadata"
    entityID="{SP_CONFIG['entity_id']}">
    <md:SPSSODescriptor
        AuthnRequestsSigned="false"
        WantAssertionsSigned="true"
        protocolSupportEnumeration="urn:oasis:names:tc:SAML:2.0:protocol">
        <md:NameIDFormat>
            urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress
        </md:NameIDFormat>
        <md:AssertionConsumerService
            Binding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST"
            Location="{SP_CONFIG['acs_url']}"
            index="0"
            isDefault="true"/>
        <md:SingleLogoutService
            Binding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-Redirect"
            Location="{SP_CONFIG['slo_url']}"/>
    </md:SPSSODescriptor>
</md:EntityDescriptor>"""

    response = make_response(metadata)
    response.headers['Content-Type'] = 'application/xml'
    return response


@app.route('/protected')
def protected():
    """Example protected route that requires SAML authentication."""
    if 'user' not in session or not session.get('authenticated'):
        return redirect(f'/saml/login?next=/protected')

    user = session['user']
    return jsonify({
        'message': 'This is a protected resource',
        'user': user,
    })


# ============================================================
# Helper: Login Required Decorator
# ============================================================
def login_required(f):
    """Decorator to require SAML authentication for a route."""
    from functools import wraps

    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'user' not in session or not session.get('authenticated'):
            return redirect(f'/saml/login?next={request.path}')
        return f(*args, **kwargs)

    return decorated_function


